function autoFormatTime(d){let O=d['value']['replace'](/\D/g,'');switch(O['length']>0x4&&(O=O['slice'](0x0,0x4)),O['length']){case 0x0:case 0x1:case 0x2:d['value']=O;break;case 0x3:if(parseInt(O['slice'](0x0,0x2),0xa)<=0x17)d['value']=O['slice'](0x0,0x2)+':'+O['slice'](0x2);else{let h=O['slice'](0x0,0x1)['padStart'](0x2,'0'),D=O['slice'](0x1);d['value']=h+':'+D;}break;case 0x4:let n=O['slice'](0x0,0x2),X=O['slice'](0x2);d['value']=n+':'+X;}}function transformTimeValue(d){let O=d['trim']();if(/^\d{2}$/['test'](O))return O[0x0]['padStart'](0x2,'0')+':'+O[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](O))return 0x3===O['length']?parseInt(O['slice'](0x0,0x2),0xa)<=0x17?O['slice'](0x0,0x2)+':'+O['slice'](0x2):O['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+O['slice'](0x1):O['slice'](0x0,0x2)+':'+O['slice'](0x2);if(O['includes'](':')){let [n,X]=O['split'](':');return X||(X='00'),n=n['padStart'](0x2,'0'),X=X['padStart'](0x2,'0'),n+':'+X;}return O;}